  public CPCalculator(@NotNull final TestsWithParametersAndConfiguration settings) {
    mySettings = settings;
    myTestsWithParams = settings.myTests2Run;
    myRepo = settings.myRepo;
  }

  public List<String> calculate() {
    boolean doINeedMPS = myTestsWithParams.getParameters().needsMPS();
    List<String> classpath = (doINeedMPS ? calcForPlatformWithMPS() : calcForPlatformWithoutMPS());
    return ListSequence.fromList(myTestsWithParams.getParameters().getClassPath()).union(ListSequence.fromList(classpath)).toListSequence();
  }

  private List<String> calcForPlatformWithoutMPS() {
    final List<String> classpath = ListSequence.fromList(new LinkedList<String>());
    // when no MPS is started, we just build a regular Java classpath with everything test classes may need. 
    myRepo.getModelAccess().runReadAction(new Runnable() {
      public void run() {
        Set<SModule> uniqueModules = SetSequence.fromSet(new HashSet<SModule>());
        List<SModuleReference> requiredModules = new ArrayList<SModuleReference>(myTestsWithParams.getRequiredModules());
        requiredModules.add(MODULE_WITH_EXECUTORS());
        for (SModuleReference testModule : requiredModules) {
          SModule module = testModule.resolve(myRepo);
          if (module != null) {
            SetSequence.fromSet(uniqueModules).addElement(module);
          } else {
            String m = String.format("No test module %s is available, execution classpath may be invalid.", testModule.getModuleName());
            if (LOG.isEnabledFor(Level.WARN)) {
              LOG.warn(m);
            }
          }
        }
        ListSequence.fromList(classpath).addSequence(ListSequence.fromList(Java_Command.getClasspath(uniqueModules)));
      }
    });
    return classpath;
  }

  private List<String> calcForPlatformWithMPS() {
    final SModuleReference moduleWithExecutors = MODULE_WITH_EXECUTORS();
    final List<String> classpath = ListSequence.fromList(new LinkedList<String>());
    // WithPlatformTestExecutor starts IDEA, therefore needs it in CP 
    ListSequence.fromList(classpath).addSequence(ListSequence.fromList(collectFromLibFolder()).distinct());
    // Module classpath would get managed by IdeaEnvironment based on set of modules to load 
    // 
    // next is to ensure TestExecutor is loaded. Though it's part of execution plugin, it's a regular mps module 
    // and is managed by MPS classloader once MPS starts, while we need it first, to start MPS. 
    myRepo.getModelAccess().runReadAction(new Runnable() {
      public void run() {
        SModule m = moduleWithExecutors.resolve(myRepo);
        if (m != null) {
          ListSequence.fromList(classpath).addSequence(ListSequence.fromList(Java_Command.getClasspath(Sequence.<SModule>singleton(m))));
        } else {
          String msg = String.format("No test module %s is available, execution classpath may be invalid.", moduleWithExecutors.getModuleName());
          // we likely to fail anyway, error is better than warn 
          if (LOG.isEnabledFor(Level.ERROR)) {
            LOG.error(msg);
          }
        }
      }
    });
    return classpath;
  }

  private List<String> collectFromLibFolder() {
    LinkedHashSet<String> libPaths = new LinkedHashSet<String>();
    // mps lib and platform lib may be the same 
    libPaths.add(PathManager.getPlatformLibPath());
    libPaths.add(PathManager.getLibPath());
    libPaths.add(PathManager.getLibExtPath());
    List<String> rv = new ArrayList<String>();
    for (String lp : libPaths) {
      File libDir = new File(lp);
      if (!(libDir.isDirectory())) {
        continue;
      }
      for (File f : libDir.listFiles()) {
        if (isJarOrZip(f)) {
          rv.add(f.getPath());
        }
      }
      // don't get into nested dir. though this is different e.g. 
      // from ant tasks (see MPSClasspathUtil#gatherAllClassesAndJarsUnder() 
      // this is how it was with ClassloaderUtil.addIDEALibraries that used to be here. 
    }
    return rv;
  }

  private List<String> collectFromPreInstalledPluginsFolder() {
    List<String> result = ListSequence.fromList(new ArrayList<String>());
    // XXX why pre-installed only, and not any locally-deployed (getPluginsPath())? 
    // Why not MPS's PathManager but IDEA's? 
    File preinstalledFolder = new File(com.intellij.openapi.application.PathManager.getPreInstalledPluginsPath());
    final File[] pluginFiles = preinstalledFolder.listFiles();
    if (pluginFiles != null) {
      for (final File pluginFile : pluginFiles) {
        if (!(isJarOrZip(pluginFile))) {
          File classesDir = new File(pluginFile, "classes");
          ListSequence.fromList(result).addElement(classesDir.getAbsolutePath());
          File libDir = new File(pluginFile, "lib");
          ListSequence.fromList(result).addSequence(ListSequence.fromList(gatherAllJarsUnderRoot(libDir)));
        }
      }
    }
    ListSequence.fromList(result).addSequence(ListSequence.fromList(gatherAllJarsUnderRoot(preinstalledFolder)));
    return result;
  }

  private List<String> gatherAllJarsUnderRoot(File root) {
    List<String> res = ListSequence.fromList(new ArrayList<String>());
    if (!(root.exists())) {
      return res;
    }
    File[] children = root.listFiles();
    if (children != null) {
      for (final File childFile : children) {
        if (isJarOrZip(childFile)) {
          ListSequence.fromList(res).addElement(childFile.getAbsolutePath());
        }
      }
    }

    return res;
  }

  @SuppressWarnings(value = {"HardCodedStringLiteral"})
  private static boolean isJarOrZip(File file) {
    if (file.isDirectory()) {
      return false;
    }
    final String name = file.getName();
    return StringUtil.endsWithIgnoreCase(name, ".jar") || StringUtil.endsWithIgnoreCase(name, ".zip");
  }

